#include <iostream>

using namespace std;

int main() {
    // Fast I/O
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    int n;
    if (cin >> n) {
        long long total_sum = 0;
        for (int i = 0; i < n; i++) {
            long long a;
            cin >> a;
            total_sum += a;
        }

        // Pure integer binary search
        long long left = 0, right = 10000000; // sqrt(10^14) is 10^7
        bool is_square = false;

        while (left <= right) {
            long long mid = left + (right - left) / 2;
            long long square = mid * mid;

            if (square == total_sum) {
                is_square = true;
                break;
            } else if (square < total_sum) {
                left = mid + 1;
            } else {
                right = mid - 1;
            }
        }

        if (is_square) {
            cout << "Yes\n";
        } else {
            cout << "No\n";
        }
    }

    return 0;
}

